content = BL.read_text(encoding="utf-8")

# Detect Variant A vs Variant B
if content.startswith("<div class=\"tick\">"):
    variant = "B (wrapped h2)"
elif content.startswith("<h2>"):
    variant = "A (bare h2)"
else:
    raise SystemExit(f"UNKNOWN variant — first 80 chars: {content[:80]!r}")

# Find the insertion point
if variant.startswith("B"):
    anchor = '<div class="tick">'
else:
    anchor = '<h2>'

idx = content.find(anchor)
assert idx == 0, f"topmost tick not at offset 0 (got {idx}) — variant detection wrong"

new_content = content[:idx] + NEW_TICK + content[idx:]
BL.write_text(new_content, encoding="utf-8")

# Re-verify
content2 = BL.read_text(encoding="utf-8")
assert content2.startswith(anchor), "after prepend, topmost tick no longer at offset 0"
assert "[Tick 142]" in content2
assert content2.count('<div class="tick">') >= content.count('<div class="tick">') + 1 if variant == "B" else True

print(f"OK tick 142 prepended. variant={variant}. new length={len(new_content)} (was {len(content)}). delta=+{len(new_content)-len(content)} chars")
